int numberOfArithmeticSlices(int* nums, int n) {
    if (n < 3) return 0;
    int dp = 0, ans = 0;
    for (int i = 2; i < n; i++) {
        if (nums[i]-nums[i-1] == nums[i-1]-nums[i-2]) { dp++; ans += dp; }
        else dp = 0;
    }
    return ans;
}
